use leptos::{ev::click, prelude::*};
use web_sys::Element;

// no extra parameter
pub fn highlight(el: Element) {
    let mut highlighted = false;

    let handle = el.clone().on(click, move |_| {
        highlighted = !highlighted;

        if highlighted {
            el.style(("background-color", "yellow"));
        } else {
            el.style(("background-color", "transparent"));
        }
    });
    on_cleanup(move || drop(handle));
}

// one extra parameter
pub fn copy_to_clipboard(el: Element, content: &str) {
    let content = content.to_owned();
    let handle = el.clone().on(click, move |evt| {
        evt.prevent_default();
        evt.stop_propagation();

        let _ = window().navigator().clipboard().write_text(&content);

        el.set_inner_html(&format!("Copied \"{}\"", &content));
    });
    on_cleanup(move || drop(handle));
}

// custom parameter

#[derive(Clone)]
pub struct Amount(usize);

impl From<usize> for Amount {
    fn from(value: usize) -> Self {
        Self(value)
    }
}

// a 'default' value if no value is passed in
impl From<()> for Amount {
    fn from(_: ()) -> Self {
        Self(1)
    }
}

pub fn add_dot(el: Element, amount: Amount) {
    use leptos::wasm_bindgen::JsCast;
    let el = el.unchecked_into::<web_sys::HtmlElement>();

    let handle = el.clone().on(click, move |_| {
        el.set_inner_text(&format!(
            "{}{}",
            el.inner_text(),
            ".".repeat(amount.0)
        ))
    });
    on_cleanup(move || drop(handle));
}

#[component]
pub fn SomeComponent() -> impl IntoView {
    view! {
        <p>Some paragraphs</p>
        <p>that can be clicked</p>
        <p>in order to highlight them</p>
    }
}

#[component]
pub fn App() -> impl IntoView {
    let data = "Hello World!";

    view! {
        <a href="#" use:copy_to_clipboard=data>
            "Copy \""
            {data}
            "\" to clipboard"
        </a>
        // automatically applies the directive to every root element in `SomeComponent`
        <SomeComponent use:highlight/>
        // no value will default to `().into()`
        <button use:add_dot>"Add a dot"</button>
        // can manually call `.into()` to convert to the correct type
        // (automatically calling `.into()` prevents using generics in directive functions)
        <button use:add_dot=5.into()>"Add 5 dots"</button>
    }
}

use super::*;
use sea_orm::{DbConn, entity::*, error::*};

pub async fn all_about_mutation(db: &DbConn) -> Result<(), DbErr> {
    insert_and_update(db).await?;

    println!("===== =====\n");

    save_active_model(db).await?;

    println!("===== =====\n");

    save_custom_active_model(db).await?;

    Ok(())
}

pub async fn insert_and_update(db: &DbConn) -> Result<(), DbErr> {
    let pear = fruit::ActiveModel {
        name: Set("pear".to_owned()),
        ..Default::default()
    };
    let res = Fruit::insert(pear).exec(db).await?;

    println!("Inserted: last_insert_id = {}", res.last_insert_id);

    let pear: Option<fruit::Model> = Fruit::find_by_id(res.last_insert_id).one(db).await?;

    println!("Pear: {pear:?}");

    let mut pear: fruit::ActiveModel = pear.unwrap().into();
    pear.name = Set("Sweet pear".to_owned());

    let pear: fruit::Model = pear.update(db).await?;

    println!("Updated: {pear:?}");

    let result = pear.delete(db).await?;

    println!("Deleted: {result:?}");

    Ok(())
}

pub async fn save_active_model(db: &DbConn) -> Result<(), DbErr> {
    let banana = fruit::ActiveModel {
        name: Set("Banana".to_owned()),
        ..Default::default()
    };
    let mut banana: fruit::ActiveModel = banana.save(db).await?;

    println!("Inserted: {banana:?}");

    banana.name = Set("Banana Mongo".to_owned());

    let banana: fruit::ActiveModel = banana.save(db).await?;

    println!("Updated: {banana:?}");

    let result = banana.delete(db).await?;

    println!("Deleted: {result:?}");

    Ok(())
}

mod form {
    use super::fruit::*;
    use sea_orm::entity::prelude::*;

    #[derive(Clone, Debug, PartialEq, Eq, DeriveIntoActiveModel)]
    pub struct InputModel {
        pub name: String,
    }
}

async fn save_custom_active_model(db: &DbConn) -> Result<(), DbErr> {
    let pineapple = form::InputModel {
        name: "Pineapple".to_owned(),
    }
    .into_active_model();

    let pineapple = pineapple.save(db).await?;

    println!("Saved: {pineapple:?}");

    let result = pineapple.delete(db).await?;

    println!("Deleted: {result:?}");

    Ok(())
}

